import { useCallback, useEffect, useLayoutEffect, useMemo, useRef, useState } from "react";
import { useQuery, useQueries, useMutation, useQueryClient } from "@tanstack/react-query";
import { useNavigate } from "react-router-dom";
import { toast } from "sonner";
import api from "@/api/app/client";
import { userService as accountService } from "@/api/auth/userService";
import { getApiErrorMessage } from "@/api/app/apiError";
import { Trash2, Check, LayoutGrid, Plus, Building2, CalendarDays } from "lucide-react";
import { PermissionGate } from "@/components/shared/PermissionGate";
import { PERMISSIONS } from "@/constants/permissions";
import type { Project, ProjectAssignment } from "@/types/project";
import type { User } from "@/types/user";
import type { Customer } from "@/types/customer";
import { HarmonyAlertDialog } from "@/components/ui/harmony-alert-dialog";
import { HarmonyDialog } from "@/components/ui/harmony-dialog";
import { HarmonyTable, type HarmonyColumn } from "@/components/ui/harmony-table";
import { UserAvatar } from "@/components/ui/UserAvatar";
import { Button } from "@/shadcn/components/ui/button";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/shadcn/components/ui/select';
import { Input } from '@/shadcn/components/ui/input';
import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from '@/shadcn/components/ui/tooltip';
import { Badge } from '@/shadcn/components/ui/badge';
import { getAuthorizedFileUrl, cleanupBlobUrl } from "@/utils/fileUtils";
import { formatDate } from "@/utils/dateUtils";
import { queryKeys } from '@/lib/queryKeys';
import { ROUTES } from '@/lib/routes';

// eslint-disable-next-line @typescript-eslint/no-explicit-any
const extractList = (res: any): any[] => {
  const data = res?.data || res?.items || res;
  return Array.isArray(data) ? data : [];
};

interface AssignmentRow {
  id: string;
  projectId: string;
  assignmentId: string;
  rawAssignment: ProjectAssignment;
  customerId?: string;
  customerName: string;
  projectName: string;
  employeeName: string;
  employeeId: string;
  employeeFirstName?: string;
  employeeLastName?: string;
  employeeHasPicture: boolean;
  startDate: string;
  endDate: string;
}

const Assignments = () => {
  const queryClient = useQueryClient();
  const navigate = useNavigate();
  const [selectedProject, setSelectedProject] = useState("");
  const [selectedEmployee, setSelectedEmployee] = useState("");
  const [startDate, setStartDate] = useState(new Date().toISOString().split("T")[0]);
  const [endDate, setEndDate] = useState("");
  const [isAssignDialogOpen, setIsAssignDialogOpen] = useState(false);
  const [assignmentToDelete, setAssignmentToDelete] = useState<{ projectId: string; assignmentId: string; name: string } | null>(null);
  const [assignmentToComplete, setAssignmentToComplete] = useState<{ projectId: string; assignmentId: string; name: string } | null>(null);

  const { data: projects = [], isError: projectsError } = useQuery<Project[]>({
    queryKey: queryKeys.projects.all(),
    queryFn: () => api.get("/projects").then(r => extractList(r.data)),
  });

  const { data: employees = [], isError: employeesError } = useQuery<User[]>({
    queryKey: queryKeys.employees(),
    queryFn: () => accountService.getEmployees().then(data => Array.isArray(data) ? data as User[] : []),
  });

  const { data: customers = [], isError: customersError } = useQuery<Customer[]>({
    queryKey: queryKeys.customers.all(),
    queryFn: () => api.get("/customers").then(r => extractList(r.data)),
  });

  const [logoBlobUrls, setLogoBlobUrls] = useState<Record<string, { url: string; fileId: string }>>({});
  const logoBlobUrlsRef = useRef(logoBlobUrls);
  useLayoutEffect(() => { logoBlobUrlsRef.current = logoBlobUrls; });

  useEffect(() => {
    let isMounted = true;
    const fetchLogos = async () => {
      const updates: Record<string, { url: string; fileId: string }> = {};
      for (const c of customers) {
        if (!isMounted) break;
        if (c.logoFileId) {
          const current = logoBlobUrlsRef.current[c.id];
          if (!current || current.fileId !== c.logoFileId) {
            if (current?.url) cleanupBlobUrl(current.url);
            const blobUrl = await getAuthorizedFileUrl(c.logoFileId);
            if (!isMounted) {
              if (blobUrl) cleanupBlobUrl(blobUrl);
              break;
            }
            if (blobUrl) updates[c.id] = { url: blobUrl, fileId: c.logoFileId };
          }
        }
      }
      if (isMounted && Object.keys(updates).length > 0) setLogoBlobUrls(prev => ({ ...prev, ...updates }));
    };
    if (customers.length > 0) fetchLogos();
    return () => { isMounted = false; };
  }, [customers]); // eslint-disable-line react-hooks/exhaustive-deps

  useEffect(() => {
    return () => { Object.values(logoBlobUrlsRef.current).forEach(item => cleanupBlobUrl(item.url)); };
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  const assignmentQueries = useQueries({
    queries: projects.map(p => ({
      queryKey: queryKeys.projects.assignments(p.id),
      queryFn: () => api.get(`/projects/${p.id}/assignments`).then(r => {
        const data = r.data.data || r.data;
        return Array.isArray(data) ? data as ProjectAssignment[] : [];
      }),
    })),
  });

  const assignmentsMap = useMemo(() => {
    return projects.reduce((acc, p, i) => {
      acc[p.id] = assignmentQueries[i]?.data ?? [];
      return acc;
    }, {} as Record<string, ProjectAssignment[]>);
  }, [projects, assignmentQueries]);

  const assignMutation = useMutation({
    mutationFn: ({ projectId, employeeId, startDate, endDate }: {
      projectId: string; employeeId: string; startDate: string; endDate: string | null;
    }) => api.post(`/projects/${projectId}/assignments`, {
      UserProfileId: employeeId,
      StartDate: startDate,
      EndDate: endDate || null,
    }),
    onSuccess: (_, { projectId }) => {
      queryClient.invalidateQueries({ queryKey: queryKeys.projects.assignments(projectId) });
      toast.success("Assigned successfully");
      setSelectedEmployee("");
      setSelectedProject("");
      setEndDate("");
      setIsAssignDialogOpen(false);
    },
    onError: (err) => toast.error(getApiErrorMessage(err, "Assignment failed")),
  });

  const completeMutation = useMutation({
    mutationFn: ({ projectId, assignmentId }: { projectId: string; assignmentId: string }) =>
      api.patch(`/projects/${projectId}/assignments/${assignmentId}/end`),
    onMutate: async ({ projectId, assignmentId }) => {
      await queryClient.cancelQueries({ queryKey: queryKeys.projects.assignments(projectId) });
      const previous = queryClient.getQueryData<ProjectAssignment[]>(queryKeys.projects.assignments(projectId));
      queryClient.setQueryData<ProjectAssignment[]>(queryKeys.projects.assignments(projectId), old =>
        (old ?? []).map(a => a.id === assignmentId ? { ...a, endDate: new Date().toISOString().split('T')[0] } : a)
      );
      return { previous, projectId };
    },
    onError: (err, _, context) => {
      if (context) queryClient.setQueryData(queryKeys.projects.assignments(context.projectId), context.previous);
      toast.error(getApiErrorMessage(err, "Failed to complete assignment"));
    },
    onSuccess: () => setAssignmentToComplete(null),
    onSettled: (_, __, { projectId }) => {
      queryClient.invalidateQueries({ queryKey: queryKeys.projects.assignments(projectId) });
    },
  });

  const deleteMutation = useMutation({
    mutationFn: ({ projectId, assignmentId }: { projectId: string; assignmentId: string }) =>
      api.delete(`/projects/${projectId}/assignments/${assignmentId}`),
    onMutate: async ({ projectId, assignmentId }) => {
      await queryClient.cancelQueries({ queryKey: queryKeys.projects.assignments(projectId) });
      const previous = queryClient.getQueryData<ProjectAssignment[]>(queryKeys.projects.assignments(projectId));
      queryClient.setQueryData<ProjectAssignment[]>(queryKeys.projects.assignments(projectId), old =>
        (old ?? []).filter(a => a.id !== assignmentId)
      );
      return { previous, projectId };
    },
    onError: (err, _, context) => {
      if (context) queryClient.setQueryData(queryKeys.projects.assignments(context.projectId), context.previous);
      toast.error(getApiErrorMessage(err, "Failed to remove assignment"));
    },
    onSuccess: () => setAssignmentToDelete(null),
    onSettled: (_, __, { projectId }) => {
      queryClient.invalidateQueries({ queryKey: queryKeys.projects.assignments(projectId) });
    },
  });

  const assign = () => {
    if (!selectedProject || !selectedEmployee) {
      toast.error("Please select both a project and an employee");
      return;
    }
    assignMutation.mutate({ projectId: selectedProject, employeeId: selectedEmployee, startDate, endDate: endDate || null });
  };

  const handleCompleteAssignment = (projectId: string, assignmentId: string, employeeName: string) => {
    setAssignmentToComplete({ projectId, assignmentId, name: employeeName });
  };

  const handleDeleteAssignment = (projectId: string, assignmentId: string) => {
    const assignment = assignmentsMap[projectId]?.find(a => a.id === assignmentId);
    const name = assignment ? getEmployeeName(assignment) : "this assignment";
    setAssignmentToDelete({ projectId, assignmentId, name });
  };

  const getEmployeeName = useCallback((assignment: ProjectAssignment) => {
    const emp = employees.find(
      (e) => e.userProfileId === assignment.employeeId || e.id === assignment.employeeId
    );
    if (emp) {
      return emp.fullName || emp.name ||
        `${emp.firstName || ""} ${emp.lastName || ""}`.trim() ||
        emp.email || "Unknown";
    }
    return assignment.employeeId?.slice(0, 8) + "..." || "Unknown";
  }, [employees]);

  const assignmentColumns: HarmonyColumn<AssignmentRow>[] = [
    {
      key: 'customerName',
      header: 'Customer',
      width: 200,
      sortable: false,
      renderCell: ({ row }) => (
        <div className="flex items-center gap-2">
          <div className="h-6 w-6 shrink-0 rounded-md border border-border bg-muted/50 flex items-center justify-center overflow-hidden">
            {row.customerId && logoBlobUrls[row.customerId]?.url
              ? <img src={logoBlobUrls[row.customerId].url} alt="" className="h-full w-full object-cover" />
              : <Building2 size={13} className="text-muted-foreground/50" />
            }
          </div>
          <span className="font-medium text-foreground truncate">{row.customerName}</span>
        </div>
      ),
    },
    {
      key: 'projectName',
      header: 'Project',
      width: 180,
      sortable: false,
      renderCell: ({ row }) => row.projectName,
    },
    {
      key: 'employeeName',
      header: 'Member',
      fill: true,
      sortable: false,
      renderCell: ({ row }) => (
        <div className="flex items-center gap-2">
          <UserAvatar
            userId={row.employeeId}
            firstName={row.employeeFirstName}
            lastName={row.employeeLastName}
            cacheKey={row.employeeHasPicture ? undefined : null}
            className="h-6 w-6 shrink-0"
          />
          <span>{row.employeeName}</span>
        </div>
      ),
    },
    {
      key: 'startDate',
      header: 'Start Date',
      width: 110,
      sortable: false,
      renderCell: ({ row }) => row.startDate,
    },
    {
      key: 'endDate',
      header: 'End Date',
      width: 110,
      sortable: false,
      renderCell: ({ row }) => row.endDate !== '—'
        ? <Badge variant="outline" className="text-xs text-muted-foreground">{row.endDate}</Badge>
        : <Badge variant="outline" className="text-xs border-emerald-200 text-emerald-700 dark:border-emerald-800 dark:text-emerald-400">Active</Badge>,
    },
    {
      key: 'actions',
      header: 'Actions',
      width: 80,
      sortable: false,
      resizable: false,
      cellClass: 'rdg-cell-actions',
      renderCell: ({ row }) => (
        <TooltipProvider>
          <div className="flex items-center gap-0.5">
            <Tooltip>
              <TooltipTrigger asChild>
                <Button
                  size="icon-xs"
                  variant="ghost"
                  className="text-muted-foreground hover:text-foreground"
                  onClick={(e) => { e.stopPropagation(); navigate(ROUTES.workScheduleForUser(row.employeeId)); }}
                >
                  <CalendarDays size={12} />
                </Button>
              </TooltipTrigger>
              <TooltipContent>View Schedule</TooltipContent>
            </Tooltip>
            {!row.rawAssignment.endDate && (
              <PermissionGate permission={PERMISSIONS.ProjectAssignment.Update} mode="disable">
                <Tooltip>
                  <TooltipTrigger asChild>
                    <Button
                      size="icon-xs"
                      variant="ghost"
                      className="text-muted-foreground hover:text-emerald-600 hover:bg-emerald-50 dark:hover:text-emerald-400 dark:hover:bg-emerald-950/40"
                      onClick={(e) => { e.stopPropagation(); handleCompleteAssignment(row.projectId, row.assignmentId, row.employeeName); }}
                    >
                      <Check size={12} />
                    </Button>
                  </TooltipTrigger>
                  <TooltipContent>Mark Complete</TooltipContent>
                </Tooltip>
              </PermissionGate>
            )}
            <PermissionGate permission={PERMISSIONS.ProjectAssignment.Delete} mode="disable">
              <Tooltip>
                <TooltipTrigger asChild>
                  <Button
                    size="icon-xs"
                    variant="ghost"
                    className="text-muted-foreground hover:text-destructive hover:bg-destructive/10"
                    onClick={(e) => { e.stopPropagation(); handleDeleteAssignment(row.projectId, row.assignmentId); }}
                  >
                    <Trash2 size={12} />
                  </Button>
                </TooltipTrigger>
                <TooltipContent>Delete</TooltipContent>
              </Tooltip>
            </PermissionGate>
          </div>
        </TooltipProvider>
      ),
    },
  ];

  const gridRows = useMemo(() => {
    const rows: AssignmentRow[] = [];
    projects.forEach((p) => {
      const customer = customers.find((c) => c.id === p.customerId);
      const assignments = assignmentsMap[p.id] || [];
      assignments.forEach((a, index: number) => {
        const emp = employees.find(
          (e) => e.userProfileId === a.employeeId || e.id === a.employeeId
        );
        rows.push({
          id: a.id || `${p.id}-${index}`,
          projectId: p.id,
          assignmentId: a.id,
          rawAssignment: a,
          customerId: customer?.id,
          customerName: customer?.name ?? "N/A",
          projectName: p.name,
          employeeName: getEmployeeName(a),
          employeeId: a.employeeId,
          employeeFirstName: emp?.firstName ?? undefined,
          employeeLastName: emp?.lastName ?? undefined,
          employeeHasPicture: emp?.profilePictureUrl != null,
          startDate: a.startDate ? formatDate(a.startDate) : "—",
          endDate: a.endDate ? formatDate(a.endDate) : "—",
        });
      });
    });
    return rows;
  }, [projects, customers, assignmentsMap, employees, getEmployeeName]);

  return (
    <div className="page-wrapper flex flex-col" style={{ gap: 'var(--section-padding)' }}>
      <div className="page-header">
        <div className="flex items-center gap-3">
          <div className="size-12 flex items-center justify-center rounded-lg bg-primary/10 shrink-0">
            <LayoutGrid className="w-7 h-7 text-primary" />
          </div>
          <div>
            <h1 className="page-title">Project Assignments</h1>
            <p className="page-subtitle">Manage and monitor employee-to-project resource allocations</p>
          </div>
        </div>
        <PermissionGate permission={PERMISSIONS.ProjectAssignment.Create} mode="disable">
          <Button onClick={() => setIsAssignDialogOpen(true)}>
            <Plus size={16} /> New Assignment
          </Button>
        </PermissionGate>
      </div>

      <HarmonyDialog
        open={isAssignDialogOpen}
        onOpenChange={setIsAssignDialogOpen}
        title="New Assignment"
        description="Assign an employee to a project with a start date."
        size="lg"
        onSubmit={assign}
        submitLabel="Execute Assignment"
        isSubmitting={assignMutation.isPending}
        onCancel={() => setIsAssignDialogOpen(false)}
      >
        <div className="grid grid-cols-1 gap-4">
          <div className="space-y-2">
            <label className="form-label">Employee</label>
            <Select value={selectedEmployee} onValueChange={setSelectedEmployee}>
              <SelectTrigger className="w-full">
                <SelectValue placeholder="Select employee..." />
              </SelectTrigger>
              <SelectContent>
                {employees.map((emp) => {
                  const id = String(emp.userProfileId || emp.id || emp.userId || "");
                  const name = emp.fullName || emp.name || `${emp.firstName || ""} ${emp.lastName || ""}`.trim() || emp.email || id;
                  return <SelectItem key={id} value={id}>{name}</SelectItem>;
                })}
              </SelectContent>
            </Select>
          </div>
          <div className="space-y-2">
            <label className="form-label">Project</label>
            <Select value={selectedProject} onValueChange={setSelectedProject}>
              <SelectTrigger className="w-full">
                <SelectValue placeholder="Select project..." />
              </SelectTrigger>
              <SelectContent>
                {projects.map((p) => (
                  <SelectItem key={p.id} value={p.id}>{p.name}</SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>
          <div className="space-y-2">
            <label className="form-label">Start Date</label>
            <Input
              type="date"
              value={startDate}
              onChange={(e) => setStartDate(e.target.value)}
            />
          </div>
        </div>
      </HarmonyDialog>

      {(projectsError || employeesError || customersError) && (
        <p className="text-sm text-destructive p-4">Failed to load data. Please refresh the page.</p>
      )}

      <HarmonyTable<AssignmentRow>
        rows={gridRows}
        columns={assignmentColumns}
        rowKeyGetter={(row) => row.id}
        searchPlaceholder="Search assignments…"
        emptyMessage="No assignments found"
      />

      <HarmonyAlertDialog
        open={!!assignmentToComplete}
        onOpenChange={(open) => { if (!open) setAssignmentToComplete(null); }}
        variant="warning"
        title="Mark as Completed"
        description={`Mark ${assignmentToComplete?.name ?? "this employee"}'s work on this project as completed today? This will set the end date and cannot be undone.`}
        actionLabel="Mark Complete"
        onAction={() => { if (assignmentToComplete) completeMutation.mutate(assignmentToComplete); }}
        isActioning={completeMutation.isPending}
      />

      <HarmonyAlertDialog
        open={!!assignmentToDelete}
        onOpenChange={(open) => { if (!open) setAssignmentToDelete(null); }}
        variant="danger"
        title="Delete Assignment"
        description={`This will permanently remove ${assignmentToDelete?.name ?? "this assignment"} from the project. This action cannot be undone.`}
        actionLabel="Delete Assignment"
        onAction={() => { if (assignmentToDelete) deleteMutation.mutate(assignmentToDelete); }}
        isActioning={deleteMutation.isPending}
      />
    </div>
  );
};

export default Assignments;
